<template>
  <div class="onboarding-container">
    <div class="header">
      <div class="logo">
        <img src="/favicon.ico" alt="Pomelo" class="logo-img">
        <span class="logo-text">西柚 Pomelo</span>
      </div>
      <h2>Merchant Onboarding</h2>
      <p>Complete the form to join our platform</p>
    </div>
    
    <ProgressBar currentStep="2" />
    
    <div class="form-section">
      <h3>Service</h3>
      <p class="section-desc">Please select the appropriate service type</p>
      
      <el-form ref="form" :model="form" :rules="rules" label-width="180px">
        <el-row>
          <el-col :span="12">
            <el-form-item label="Select School *" prop="deptId">
              <el-select v-model="form.deptId" clearable placeholder="Choose School">
                <el-option
                  v-for="item in deptList"
                  :key="item.deptId"
                  :label="item.deptName"
                  :value="item.deptId">
                </el-option>
              </el-select>
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="Principal Type *" prop="principalType">
              <el-select v-model="form.principalType" clearable placeholder="Select Type">
                <el-option
                  :key="1"
                  :label="'Person'"
                  :value="1">
                </el-option>
                <el-option
                  :key="2"
                  :label="'Company'"
                  :value="2">
                </el-option>
              </el-select>
            </el-form-item>
          </el-col>
        </el-row>
        
        <el-row>
          <el-col :span="12">
            <el-form-item label="Authorized Representative ID *" prop="legalPerCard">
              <el-input v-model="form.legalPerCard" placeholder="ID number" maxlength="20"/>
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="Authorized Representative Name *" prop="legalName">
              <el-input v-model="form.legalName" placeholder="Full legal name" maxlength="50"/>
            </el-form-item>
          </el-col>
        </el-row>
        
        <div class="form-buttons">
          <el-button class="save-draft-btn" @click="saveDraft">Save Draft</el-button>
          <div class="action-buttons">
            <el-button class="back-btn" @click="prevStep">{{leftStr}} Back</el-button>
            <el-button class="next-btn" @click="nextStep">Next ></el-button>
          </div>
        </div>
      </el-form>
    </div>
    
    <div class="footer-note">
      <p>Your information is secure and will only be used for merchant verification.</p>
    </div>
  </div>
</template>

<script>
/* eslint-disable vue/multi-word-component-names */
export default {
  name: 'Service',
  components: {
    ProgressBar: () => import('@/components/ProgressBar.vue')
  },
  data() {
    return {
      leftStr: "<",
      form: {
        deptId: '',
        principalType: '',
        legalPerCard: '',
        legalName: ''
      },
      deptList: [
        { deptId: 1, deptName: 'School of Business' },
        { deptId: 2, deptName: 'School of Engineering' },
        { deptId: 3, deptName: 'School of Arts' },
        { deptId: 4, deptName: 'School of Science' }
      ],
      rules: {
        deptId: [
          { required: true, message: "Please select school", trigger: "blur" }
        ],
        principalType: [
          { required: true, message: "Please select principal type", trigger: "blur" }
        ],
        legalPerCard: [
          { required: true, message: "Please input authorized representative ID", trigger: "blur" }
        ],
        legalName: [
          { required: true, message: "Please input authorized representative name", trigger: "blur" }
        ]
      }
    }
  },
  methods: {
    saveDraft() {
      this.$message.success('Draft saved successfully!');
    },
    prevStep() {
      this.$router.push('/business-info');
    },
    nextStep() {
      this.$refs["form"].validate((valid) => {
        if (valid) {
          // 保存当前表单数据到sessionStorage
          sessionStorage.setItem('serviceInfo', JSON.stringify(this.form));
          // 跳转到下一步
          this.$router.push('/contact');
        }
      });
    }
  },
  mounted() {
    // 从sessionStorage加载数据
    const savedData = sessionStorage.getItem('serviceInfo');
    if (savedData) {
      this.form = JSON.parse(savedData);
    }
  }
}
</script>

<style scoped>
.onboarding-container {
  background-color: #FFFFFF;
  border-radius: 12px;
  padding: 30px;
  box-shadow: 0 2px 12px 0 rgba(0, 0, 0, 0.08);
}

.header {
  text-align: center;
  margin-bottom: 30px;
}

.logo {
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 15px;
}

.logo-img {
  width: 32px;
  height: 32px;
  margin-right: 8px;
}

.logo-text {
  font-size: 20px;
  font-weight: bold;
  color: #FF6B00;
}

.header h2 {
  margin: 0 0 8px 0;
  font-size: 24px;
  color: #333333;
}

.header p {
  margin: 0;
  color: #666666;
  font-size: 14px;
}

.form-section {
  background-color: #FFFFFF;
  border-radius: 8px;
  padding: 24px;
  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.05);
}

.form-section h3 {
  margin: 0 0 8px 0;
  font-size: 18px;
  color: #333333;
}

.section-desc {
  margin: 0 0 24px 0;
  color: #666666;
  font-size: 14px;
}

.form-buttons {
  margin-top: 32px;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.action-buttons {
  display: flex;
  align-items: center;
}

.form-buttons .el-button {
  margin-left: 10px;
  padding: 0 30px;
  height: 40px;
  border-radius: 4px;
}

.action-buttons .el-button {
  margin-left: 10px;
}

.save-draft-btn {
  border: 1px solid #DCDFE6;
  background-color: #FFFFFF;
  color: #606266;
}

.back-btn {
  border: 1px solid #DCDFE6;
  background-color: #FFFFFF;
  color: #606266;
}

.next-btn {
  background-color: #FF6B00 !important;
  border: none;
  color: #FFFFFF;
}

.next-btn:hover {
  background-color: #FF8533 !important;
}

.footer-note {
  margin-top: 24px;
  text-align: center;
  font-size: 12px;
  color: #999999;
}

/* 表单内容区域样式调整 */
:deep(.el-form-item__content) {
  width: 100%;
  justify-content: space-between;
  margin-left: 0px !important;
}

/* 表单样式调整 */
:deep(.el-form-item) {
  margin-bottom: 20px;
}

:deep(.el-form-item__label) {
  font-size: 14px;
  font-weight: 500;
  color: #333333;
}

:deep(.el-input__wrapper) {
  border-radius: 6px;
}

:deep(.el-input__wrapper.is-focus) {
  box-shadow: 0 0 0 1px #FF6B00 inset !important;
}

:deep(.el-select__wrapper) {
  border-radius: 6px;
}

:deep(.el-select__wrapper.is-focus) {
  box-shadow: 0 0 0 1px #FF6B00 inset !important;
}
</style>